options.afterRender:
var queries = {
  'balthasar': 'borgbackup-job-nfs-share.service',
  'melchior': 'borgbackup-job-nfs-home.service',
  'casper': 'syncoid-home'
};
Object.keys(queries).forEach(function(key) {
  var q = encodeURIComponent('(time() - task_last_run{name="' + queries[key] + '"}) / 3600');
  fetch('/api/datasources/proxy/1/api/v1/query?query=' + q)
    .then(function(r) { return r.json(); })
    .then(function(data) {
      if (data.data && data.data.result && data.data.result.length > 0) {
        var hours = parseFloat(data.data.result[0].value[1]);
        var el = document.getElementById('status-' + key);
        var box = document.getElementById('box-' + key);
        if (el && box) {
          if (hours < 24) {
            el.textContent = 'OK';
            box.style.background = '#1a472a';
          } else if (hours < 48) {
            el.textContent = 'LATE';
            box.style.background = '#5a3000';
          } else {
            el.textContent = 'FAILED';
            box.style.background = '#5a0000';
          }
        }
      }
    })
    .catch(function() {});
});
